<template>
  <div class="canvas-annotate-page flex_1 flex_y">
    <div class="defect-image-header flex_x flex_a_center">
      <div>Canvas 看图</div>
      <el-button type="primary" size="mini" @click="handleCenterImage">图像-居中&适配</el-button>
      <el-button type="primary" size="mini" @click="handleExportImage">导出图片</el-button>
      <div class="canvas-tip">绘制矩形：在图上拖拽；测距：按住 M 键拖线；平移：空格+拖拽</div>
    </div>
    <div ref="imgBox" class="canvas-container">
      <canvas
        ref="myCanvas"
        :key="canvasKey"
        class="defect-canvas"
        @mousedown.stop
      ></canvas>
    </div>
  </div>
</template>

<script>
// src/assets 内图片需 require，不能写 /images/... 路径
const ANNOTATE_IMAGE_URL = require('@/assets/images/sky.jpg')

export default {
  name: 'CanvasAnnotate',
  data () {
    return {
      canvasKey: 0,
      canvasSelect: null
    }
  },
  mounted () {
    this.renderCanvas()
  },
  beforeDestroy () {
    if (this.canvasSelect) {
      this.canvasSelect.destroy()
      this.canvasSelect = null
    }
  },
  methods: {
    /** 参考 defectCanvasRender.renderDefectCanvas / dataset.createCanvasSelect */
    renderCanvas () {
      this.$nextTick(() => {
        const box = this.$refs.imgBox
        if (!box || !box.offsetWidth || !box.offsetHeight) return

        if (this.canvasSelect) {
          this.canvasSelect.destroy()
        }

        this.canvasSelect = new CanvasSelect({
          el: this.$refs.myCanvas,
          width: box.offsetWidth,
          height: box.offsetHeight,
          imgSrc: ANNOTATE_IMAGE_URL,
          lock: false,
          readMode: false,
          keep: true,
          canMeasure: true,
          outLabel: true,
          rotateImage: false,
          imgBorder: '#fff',
          imgHScale: 1,
          imgVScale: 1,
          axesUnit: 'mm',
          hAxesRatio: 1,
          vAxesRatio: 1,
          needAxes: false,
          padding: 16,
          labelMaxLen: 9999,
          labelFont: '22px Arial',
          inputBox: box, // 输入框容器最好是canvas的父级元素--而且是相对/绝对/固定定位的元素---这样才能正确显示
        })

        const hAxesRatio = 1
        const vAxesRatio = 1
        // 测量文字显示逻辑
        this.canvasSelect.measureTextGetter = (shape) => {
          let x = shape.coor[0][0] - shape.coor[1][0];
          let y = shape.coor[0][1] - shape.coor[1][1];
          x *= hAxesRatio;
          y *= vAxesRatio;
          let distance = Math.sqrt(x * x + y * y);
          return `X: ${Math.abs(x).toFixed(2)}px  Y: ${Math.abs(y).toFixed(
            2
          )}px Length: ${distance.toFixed(2)}px`;
        };

        // 矩形标注
        this.canvasSelect.createType = 1
        this.canvasSelect.setData([])
      })
    },

    handleCenterImage () {
      if (this.canvasSelect) {
        this.canvasSelect.fitZoom()
      }
    },

    /** 参考 dataset/index.vue exportCanvasImage */
    handleExportImage () {
      if (!this.canvasSelect) return
      const dataUrl = this.canvasSelect.exportCanvasImage(null, 32)
      if (!dataUrl) {
        this.$message.error('导出失败')
        return
      }
      const link = document.createElement('a')
      link.download = `sky_${Date.now()}.png`
      link.href = dataUrl
      link.click()
    }
  }
}
</script>

<style scoped>
.canvas-annotate-page {
  height: 100%;
}

.defect-image-header {
  margin-bottom: 12px;
  padding: 0 8px;
  flex-wrap: wrap;
  gap: 8px;
}

.canvas-tip {
  color: #909399;
  font-size: 12px;
  margin-left: 8px;
}

.canvas-container {
  flex: 1;
  width: 100%;
  position: relative;
  background: #323233;
}

.defect-canvas {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
}

.flex_1 {
  flex: 1;
}

.flex_y {
  display: flex;
  flex-direction: column;
}

.flex_x {
  display: flex;
  flex-direction: row;
}

.flex_a_center {
  align-items: center;
}
</style>
